const projectService = require('../projects/service');

let tasksStore = {};

function getAllTasks(projectId) {
  return tasksStore[projectId] || [];
}

function createTask(projectId, title) {
  const task = { id: randomUUID(), title, status: 'todo' };
  if (!tasksStore[projectId]) {
    tasksStore[projectId] = [];
  }
  tasksStore[projectId].push(task);
  return task;
}

function updateTask(projectId, taskId, updates) {
  const projectTasks = tasksStore[projectId];
  if (!projectTasks) {
    return null;
  }

  const taskIndex = projectTasks.findIndex(task => task.id === taskId);
  if (taskIndex === -1) {
    return null;
  }

  const updatedTask = { ...projectTasks[taskIndex], ...updates };
  projectTasks[taskIndex] = updatedTask;
  return updatedTask;
}

module.exports = {
  getAllTasks,
  createTask,
  updateTask,
};
